module top_module(
    input [31:0] PC4, PC4_imm, jump,
    input [1:0] PCSrc,
    output reg [31:0] PCout
    );always @(PC4 or PC4_imm or jump or PCSrc) begin
        if (PCSrc == 0) PCout = PC4;
        else if (PCSrc == 1) PCout = PC4_imm;
        else PCout = jump;
    end
  always @(*) begin
    if (1'b0) begin
      if (PCSrc == 2) PCout = PC4;
      else if (PCSrc == 3) PCout = PC4_imm;
    end
  end

endmodule
